'use client';
        import type { NextPage } from 'next';
import { useMemo, type CSSProperties } from 'react';
import Image from "next/image";


export type ArrowLeftSLineType = {
  className?: string;
  editText?: string;
  rightIcon?: boolean;
  leftIcon?: boolean;

  /** Variant props */
  onlyIcon?: CSSProperties['onlyIcon'];
  size?: CSSProperties['size'];
  state?: CSSProperties['state'];
  style?: CSSProperties['style'];
  type?: CSSProperties['type'];

  /** Style props */
  arrowLeftSLineFlex?: CSSProperties['flex'];
  arrowLeftSLineAlignSelf?: CSSProperties['alignSelf'];
}

const getArrowLeftSLineStyle = (styleKey:string) => {
switch(styleKey) {case "Primary-Ghost-Default-Medium 40-Off":return "[&]:shadow-[unset] [&]:bg-[unset]";
case "Primary-Stroke-Default-Medium 40-Off":return "[&]:bg-[transparent] [&]:border-neutral-800 [&]:border-solid [&]:border-[1px]";
case "Neutral-Filled-Default-Medium 40-Off":return "[&]:shadow-[0px_1px_2px_rgba(82,_88,_102,_0.06)] [&]:bg-bg-surface-700 [&]:[border:none] [&]:z-[2] [&]:shrink-0";}
};
const getArrowLeftSLineIconStyle = (styleKey:string) => {
switch(styleKey) {case "Primary-Ghost-Default-Medium 40-Off":
case "Primary-Stroke-Default-Medium 40-Off":return "[&]:[filter:brightness(0)_saturate(100%)_invert(11%)_sepia(5%)_saturate(4911%)_hue-rotate(202deg)_brightness(94%)_contrast(85%)] [&]:shrink-0";}
};
const getTextContainerStyle = (styleKey:string) => {
switch(styleKey) {case "Primary-Ghost-Default-Medium 40-Off":
case "Primary-Stroke-Default-Medium 40-Off":return "[&]:shrink-0";}
};
const getButtonTextStyle = (styleKey:string) => {
switch(styleKey) {case "Primary-Ghost-Default-Medium 40-Off":
case "Primary-Stroke-Default-Medium 40-Off":return "[&]:text-neutral-800";}
};
const getArrowRightUpLineIconStyle = (styleKey:string) => {
switch(styleKey) {case "Primary-Ghost-Default-Medium 40-Off":
case "Primary-Stroke-Default-Medium 40-Off":return "[&]:[filter:brightness(0)_saturate(100%)_invert(11%)_sepia(5%)_saturate(4911%)_hue-rotate(202deg)_brightness(94%)_contrast(85%)] [&]:hidden [&]:shrink-0";
case "Neutral-Filled-Default-Medium 40-Off":return "[&]:hidden";}
};


const ArrowLeftSLine: NextPage<ArrowLeftSLineType> = ({ className="", onlyIcon="Off", size="Medium (40)", state="Default", style="Filled", type="Primary", editText="Open Projects", rightIcon=true, leftIcon=false, arrowLeftSLineFlex, arrowLeftSLineAlignSelf }) => {
const variantKey = [type, style, state, size, onlyIcon].join('-');

  const arrowLeftSLineStyle: CSSProperties = useMemo(() => {
                  return {
                    flex: arrowLeftSLineFlex,
      alignSelf: arrowLeftSLineAlignSelf
                  };
                }, [arrowLeftSLineFlex, arrowLeftSLineAlignSelf]);

  return (
    <div className={`shadow-[0px_1px_2px_rgba(55,_93,_251,_0.08)] rounded-num-10 bg-neutral-800 overflow-hidden flex items-center justify-center p-2.5 gap-1 text-center text-[14px] text-stroke-white-0 font-helvetica-now-display ${getArrowLeftSLineStyle(variantKey)} ${className}`} style={arrowLeftSLineStyle}>
      {!!leftIcon && (<Image className={`h-5 w-5 relative ${getArrowLeftSLineIconStyle(variantKey)}`} width={20} height={20} sizes="100vw" alt="" src="/arrow-left-s-line.svg" />)}
      <div className={`flex items-center justify-center py-num-0 px-num-4 ${getTextContainerStyle(variantKey)}`}>
        <div className={`relative tracking-num--0_01 leading-num-20 font-medium ${getButtonTextStyle(variantKey)}`}>{editText}</div>
      </div>
      {!!rightIcon && (<Image className={`h-5 w-5 relative ${getArrowRightUpLineIconStyle(variantKey)}`} width={20} height={20} sizes="100vw" alt="" src="/arrow-right-up-line.svg" />)}
    </div>);
};

export default ArrowLeftSLine ;

